import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.Bjylvv1V.js";const p=JSON.parse('{"title":"통장 대사","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/bank-reconciliation.md","filePath":"guide/scenarios/bank-reconciliation.md","lastUpdated":1771991831000}'),l={name:"guide/scenarios/bank-reconciliation.md"};function n(i,t,s,d,h,c){return r(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="통장-대사" tabindex="-1">통장 대사 <a class="header-anchor" href="#통장-대사" aria-label="Permalink to &quot;통장 대사&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 20분 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 매월 (월말 마감 전)</p></blockquote><p>시스템(장부)에 기록된 계좌 잔액과 실제 은행 통장 잔액이 일치하는지 확인하고, 차이가 있으면 원인을 파악하여 조정하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 은행 거래내역 조회     (3분)  → 아파트뱅크에서 실제 거래 확인</span></span>
<span class="line"><span>2. 시스템 잔액 확인       (3분)  → 제예금명세서로 장부 잔액 확인</span></span>
<span class="line"><span>3. 잔액 비교             (2분)  → 통장 vs 장부 대사</span></span>
<span class="line"><span>4. 차이 원인 분석        (10분) → 미입력 전표, 미처리 수납 등 파악</span></span>
<span class="line"><span>5. 조정 처리             (2분)  → 누락 건 입력·수정</span></span></code></pre></div><hr><h2 id="_1단계-은행-거래내역-조회-3분" tabindex="-1">1단계: 은행 거래내역 조회 (3분) <a class="header-anchor" href="#_1단계-은행-거래내역-조회-3분" aria-label="Permalink to &quot;1단계: 은행 거래내역 조회 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transaction.html">은행거래내역</a> (BANK0010)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>은행거래내역 화면 진입</li><li><strong>조회 기간</strong> 설정 (해당 월 1일 ~ 말일)</li><li><strong>계좌 선택</strong> (관리비 통장, 일반 통장 등)</li><li><strong>조회</strong> 실행</li><li>거래 목록 확인: <ul><li>거래일시</li><li>적요(내용)</li><li>출금액 / 입금액</li><li>잔액</li><li>수납처리 여부</li></ul></li></ol><h3 id="최근-잔액-확인" tabindex="-1">최근 잔액 확인 <a class="header-anchor" href="#최근-잔액-확인" aria-label="Permalink to &quot;최근 잔액 확인&quot;">​</a></h3><p>화면 상단의 <strong>최근잔액조회</strong>에서 해당 계좌의 최신 잔액을 확인합니다. 이 잔액은 조회 기간과 무관하게 가장 최근 거래 기준입니다.</p><div class="tip custom-block"><p class="custom-block-title">계좌조회 로그</p><p>거래내역이 조회되지 않으면 <strong>계좌조회로그</strong>를 확인하세요. 거래 없음, 시스템 오류, 비밀번호 오류 등 원인을 파악할 수 있습니다.</p></div><hr><h2 id="_2단계-시스템-잔액-확인-3분" tabindex="-1">2단계: 시스템 잔액 확인 (3분) <a class="header-anchor" href="#_2단계-시스템-잔액-확인-3분" aria-label="Permalink to &quot;2단계: 시스템 잔액 확인 (3분)&quot;">​</a></h2><h3 id="제예금명세서" tabindex="-1">제예금명세서 <a class="header-anchor" href="#제예금명세서" aria-label="Permalink to &quot;제예금명세서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 제예금명세서 (ACCT2100)</p></blockquote><p>계좌별로 회계 장부에 기록된 잔액을 확인합니다.</p><h3 id="총계정원장" tabindex="-1">총계정원장 <a class="header-anchor" href="#총계정원장" aria-label="Permalink to &quot;총계정원장&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/ledger.html">장부관리</a> &gt; 총계정원장 (ACCT3010)</p></blockquote><p>보통예금 계정의 일별 차변·대변·잔액을 확인합니다.</p><hr><h2 id="_3단계-잔액-비교-2분" tabindex="-1">3단계: 잔액 비교 (2분) <a class="header-anchor" href="#_3단계-잔액-비교-2분" aria-label="Permalink to &quot;3단계: 잔액 비교 (2분)&quot;">​</a></h2><p>아래 표를 작성하여 비교합니다.</p><table tabindex="0"><thead><tr><th>계좌</th><th>통장 잔액 (은행)</th><th>장부 잔액 (시스템)</th><th>차이</th></tr></thead><tbody><tr><td>관리비 통장</td><td>○○○원</td><td>○○○원</td><td>○○원</td></tr><tr><td>일반 통장</td><td>○○○원</td><td>○○○원</td><td>○○원</td></tr><tr><td>기타</td><td>○○○원</td><td>○○○원</td><td>○○원</td></tr></tbody></table><p><strong>차이가 0원이면</strong> → 대사 완료, 5단계로 이동할 필요 없음</p><p><strong>차이가 있으면</strong> → 4단계에서 원인 분석</p><hr><h2 id="_4단계-차이-원인-분석-10분" tabindex="-1">4단계: 차이 원인 분석 (10분) <a class="header-anchor" href="#_4단계-차이-원인-분석-10분" aria-label="Permalink to &quot;4단계: 차이 원인 분석 (10분)&quot;">​</a></h2><h3 id="주요-원인과-확인-방법" tabindex="-1">주요 원인과 확인 방법 <a class="header-anchor" href="#주요-원인과-확인-방법" aria-label="Permalink to &quot;주요 원인과 확인 방법&quot;">​</a></h3><table tabindex="0"><thead><tr><th>원인</th><th>증상</th><th>확인 방법</th></tr></thead><tbody><tr><td><strong>미입력 지출 전표</strong></td><td>통장 잔액 &lt; 장부 잔액</td><td>통장 출금 내역 중 전표 미입력 건 찾기</td></tr><tr><td><strong>미입력 수납</strong></td><td>통장 잔액 &gt; 장부 잔액</td><td>통장 입금 내역 중 수납 미처리 건 찾기</td></tr><tr><td><strong>이체 시차</strong></td><td>월말 이체가 다음 달에 반영</td><td>이체 요청일 vs 실제 출금일 비교</td></tr><tr><td><strong>카드 결제 시차</strong></td><td>승인일 ≠ 결제일</td><td>카드 매출전표 날짜 확인</td></tr><tr><td><strong>이자 수입 미반영</strong></td><td>소액 차이</td><td>통장 이자 내역 전표 입력 누락</td></tr><tr><td><strong>수수료 미반영</strong></td><td>소액 차이</td><td>이체 수수료, 카드 수수료 전표 입력 누락</td></tr><tr><td><strong>가수금 미정리</strong></td><td>입금 있지만 수납 미처리</td><td>가수금관리(RECP1051) 확인</td></tr></tbody></table><h3 id="분석-절차" tabindex="-1">분석 절차 <a class="header-anchor" href="#분석-절차" aria-label="Permalink to &quot;분석 절차&quot;">​</a></h3><ol><li>은행거래내역(BANK0010)에서 해당 월 거래를 <strong>한 건씩</strong> 확인</li><li>각 거래의 <strong>수납처리 여부</strong> 칼럼 확인 <ul><li>처리됨 → OK</li><li>미처리 → 누락 건으로 표시</li></ul></li><li>전표관리(ACCT2010)에서 해당 월 전표 목록과 대조</li><li>통장에는 있지만 전표에 없는 건 → <strong>미입력 전표</strong></li><li>전표에는 있지만 통장에 없는 건 → <strong>이체 시차</strong> 또는 <strong>오류 전표</strong></li></ol><hr><h2 id="_5단계-조정-처리-2분" tabindex="-1">5단계: 조정 처리 (2분) <a class="header-anchor" href="#_5단계-조정-처리-2분" aria-label="Permalink to &quot;5단계: 조정 처리 (2분)&quot;">​</a></h2><p>차이 원인별로 조정합니다.</p><h3 id="미입력-전표-추가" tabindex="-1">미입력 전표 추가 <a class="header-anchor" href="#미입력-전표-추가" aria-label="Permalink to &quot;미입력 전표 추가&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표입력 (ACCT2010)</p></blockquote><p>누락된 지출/수입 전표를 입력합니다. 상세 방법은 <a href="/guide/scenarios/expense-voucher.html">지출 전표 입력</a>을 참고하세요.</p><h3 id="미처리-수납-추가" tabindex="-1">미처리 수납 추가 <a class="header-anchor" href="#미처리-수납-추가" aria-label="Permalink to &quot;미처리 수납 추가&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/process.html">수납처리</a> (RECP1010)</p></blockquote><p>미처리 입금 건을 수납 처리합니다. 상세 방법은 <a href="/guide/scenarios/collection.html">수납 처리</a>를 참고하세요.</p><h3 id="이체-시차-건" tabindex="-1">이체 시차 건 <a class="header-anchor" href="#이체-시차-건" aria-label="Permalink to &quot;이체 시차 건&quot;">​</a></h3><p>월말 이체 시차로 인한 차이는 별도 조정 없이 <strong>비고로 기록</strong>합니다. 다음 달 통장 대사 시 자연 해소됩니다.</p><hr><h2 id="통장-대사-체크리스트" tabindex="-1">통장 대사 체크리스트 <a class="header-anchor" href="#통장-대사-체크리스트" aria-label="Permalink to &quot;통장 대사 체크리스트&quot;">​</a></h2><ul><li>[ ] 모든 계좌의 통장 잔액을 확인했는가?</li><li>[ ] 시스템의 제예금명세서 잔액을 확인했는가?</li><li>[ ] 각 계좌별 차이가 0원인가?</li><li>[ ] 차이가 있다면 원인을 모두 파악했는가?</li><li>[ ] 누락 전표를 모두 입력했는가?</li><li>[ ] 미처리 수납을 모두 처리했는가?</li><li>[ ] 조정 후 잔액이 일치하는가?</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="은행거래내역이-조회되지-않아요" tabindex="-1">은행거래내역이 조회되지 않아요 <a class="header-anchor" href="#은행거래내역이-조회되지-않아요" aria-label="Permalink to &quot;은행거래내역이 조회되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 공인인증서 만료, IP 변경, 은행 시스템 점검 <strong>해결</strong>: 계좌조회로그를 확인하세요. IP 변경으로 서비스가 중단된 경우 아파트뱅크 지원팀에 연락하세요.</p><h3 id="소액-차이-수백-원-가-계속-남아요" tabindex="-1">소액 차이(수백 원)가 계속 남아요 <a class="header-anchor" href="#소액-차이-수백-원-가-계속-남아요" aria-label="Permalink to &quot;소액 차이(수백 원)가 계속 남아요&quot;">​</a></h3><p><strong>원인</strong>: 이체 수수료, 통장 이자, 소액 잔돈 등 <strong>해결</strong>: 통장 거래내역에서 수수료·이자 내역을 확인하고, 해당 금액만큼 전표를 입력하세요.</p><h3 id="매월-잔액이-안-맞아서-힘들어요" tabindex="-1">매월 잔액이 안 맞아서 힘들어요 <a class="header-anchor" href="#매월-잔액이-안-맞아서-힘들어요" aria-label="Permalink to &quot;매월 잔액이 안 맞아서 힘들어요&quot;">​</a></h3><p><strong>원인</strong>: 전표 입력이 수시로 누락되는 경우 <strong>해결</strong>: 지출이 발생할 때마다 <strong>즉시</strong> 전표를 입력하는 습관을 기르세요. 아파트뱅크 거래내역과 연동하면 자동으로 매칭할 수 있습니다.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/bank/transaction.html">은행거래내역</a> - 계좌 거래 조회</li><li><a href="/acct/voucher.html">전표관리</a> - 전표 입력·조회</li><li><a href="/acct/ledger.html">장부관리</a> - 총계정원장</li><li><a href="/recp/process.html">수납처리</a> - 미처리 수납</li><li><a href="/guide/scenarios/month-closing.html">월말 마감</a> - 통장 대사 후 다음 단계</li></ul>`,58)])])}const u=a(l,[["render",n]]);export{p as __pageData,u as default};
